import{_ as a,a as t,b as n,c as d}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as l,o as r,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Yandex Kanalı Ekleme","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/upload/yandex.md","filePath":"tr-TR/upload/yandex.md","lastUpdated":1781962217000}'),s={name:"tr-TR/upload/yandex.md"};function p(c,e,h,u,k,m){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="yandex-kanalı-ekleme" tabindex="-1">Yandex Kanalı Ekleme <a class="header-anchor" href="#yandex-kanalı-ekleme" aria-label="Permalink to &quot;Yandex Kanalı Ekleme&quot;">​</a></h1><h2 id="once-gerekenler" tabindex="-1">Önce Gerekenler <a class="header-anchor" href="#once-gerekenler" aria-label="Permalink to &quot;Önce Gerekenler&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gereken</th><th>Neden gerekir</th></tr></thead><tbody><tr><td>Yandex hesabı</td><td>Giriş yapmak ve Yandex Disk&#39;i yetkilendirmek için</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> ve <code>Client Secret</code> oluşturmak için</td></tr><tr><td>ImgBed alan adınız</td><td>OAuth redirect URI için</td></tr><tr><td>Kullanılabilir Yandex Disk depolama alanı</td><td>Dosyaların gerçekten saklanacağı yer</td></tr></tbody></table><h2 id="kurulum-adımları" tabindex="-1">Kurulum Adımları <a class="header-anchor" href="#kurulum-adımları" aria-label="Permalink to &quot;Kurulum Adımları&quot;">​</a></h2><h3 id="_1-yandex-oauth-app-olusturun" tabindex="-1">1. Yandex OAuth App Oluşturun <a class="header-anchor" href="#_1-yandex-oauth-app-olusturun" aria-label="Permalink to &quot;1. Yandex OAuth App Oluşturun&quot;">​</a></h3><ol><li>Yandex OAuth app oluşturma sayfasını açın:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>Giriş sayfasına yönlendirilirseniz önce Yandex hesabınızla giriş yapın.</li><li>Yeni app oluşturun.</li><li>App için tanınabilir bir ad verin, örneğin <code>imgbed-yandex</code>.</li><li>Callback veya redirect URL ayarlarını bulun.</li><li>Şunu girin:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="_2-permissions-degerlerini-kontrol-edin" tabindex="-1">2. Permissions Değerlerini Kontrol Edin <a class="header-anchor" href="#_2-permissions-degerlerini-kontrol-edin" aria-label="Permalink to &quot;2. Permissions Değerlerini Kontrol Edin&quot;">​</a></h3><p>Mevcut ImgBed Yandex entegrasyonu için <code>Yandex.Disk REST API</code> altında şu dört permission kalsın:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Amaç</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed&#39;in dosyaları app folder içinde saklamasına izin verir</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>Dosyaları ve download links değerlerini okur</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>Dosya yükler, klasör oluşturur ve dosya siler</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>Disk kotasını ve kullanılan alanı okur</td></tr></tbody></table><p><code>Yandex ID API</code> altında şu izinleri de görürseniz bunlar isteğe bağlıdır:</p><table tabindex="0"><thead><tr><th>Permission Metni</th><th>Öneri</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>İsteğe bağlı</td></tr><tr><td><code>Access to email address</code></td><td>İsteğe bağlı</td></tr></tbody></table><p>Temel yükleme, indirme, silme ve kota özellikleri çoğunlukla yukarıdaki dört <code>Yandex.Disk REST API</code> iznine bağlıdır.</p><p><img src="'+a+'" alt="Yandex Disk izinlerini yapılandırma" loading="lazy"></p><h3 id="_3-app-credentials-degerlerini-kopyalayın" tabindex="-1">3. App Credentials Değerlerini Kopyalayın <a class="header-anchor" href="#_3-app-credentials-degerlerini-kopyalayın" aria-label="Permalink to &quot;3. App Credentials Değerlerini Kopyalayın&quot;">​</a></h3><p>App oluşturulduktan sonra şunları kopyalayın:</p><table tabindex="0"><thead><tr><th>Yandex Alanı</th><th>ImgBed Alanı</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+t+'" alt="Client ID ve Secret kaydetme" loading="lazy"></p><h3 id="_4-yandex-kanalını-doldurun" tabindex="-1">4. Yandex Kanalını Doldurun <a class="header-anchor" href="#_4-yandex-kanalını-doldurun" aria-label="Permalink to &quot;4. Yandex Kanalını Doldurun&quot;">​</a></h3><p>Yükleme Ayarları&#39;nda <code>Yandex</code> seçin ve şunları doldurun:</p><table tabindex="0"><thead><tr><th>ImgBed Alanı</th><th>Ne girilir</th></tr></thead><tbody><tr><td>Channel name</td><td>Tanınabilir bir ad, örneğin <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>Şimdilik boş bırakın</td></tr><tr><td>Root directory</td><td>İsteğe bağlı. Varsayılan <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+n+'" alt="Kanal yapılandırmasını düzenleme" loading="lazy"></p><h3 id="_5-refresh-token-alın" tabindex="-1">5. Refresh Token Alın <a class="header-anchor" href="#_5-refresh-token-alın" aria-label="Permalink to &quot;5. Refresh Token Alın&quot;">​</a></h3><ol><li>ImgBed&#39;de <code>Get Token</code> düğmesine tıklayın.</li><li>Bağlamak istediğiniz Yandex hesabıyla giriş yapın.</li><li>Yetkilendirme istemini onaylayın.</li><li>Callback sayfası bir <code>Refresh Token</code> gösterir.</li><li>Bunu kopyalayın.</li><li>ImgBed&#39;e dönüp <code>Refresh Token</code> alanına yapıştırın.</li></ol><p><img src="'+d+`" alt="Yetkilendirme sonrası refresh token kopyalama" loading="lazy"></p><h3 id="_6-kanalı-kaydedin" tabindex="-1">6. Kanalı Kaydedin <a class="header-anchor" href="#_6-kanalı-kaydedin" aria-label="Permalink to &quot;6. Kanalı Kaydedin&quot;">​</a></h3><p>Tüm alanlar dolduktan sonra kanalı kaydedin.</p><h2 id="kısa-akıs" tabindex="-1">Kısa Akış <a class="header-anchor" href="#kısa-akıs" aria-label="Permalink to &quot;Kısa Akış&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console&#39;u aç</span></span>
<span class="line"><span>-&gt; App oluştur</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback ekle</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions değerlerini kontrol et</span></span>
<span class="line"><span>-&gt; Client ID ve Client Secret kopyala</span></span>
<span class="line"><span>-&gt; Client ID / Client Secret değerlerini ImgBed&#39;e gir</span></span>
<span class="line"><span>-&gt; Get Token tıkla</span></span>
<span class="line"><span>-&gt; Callback sayfasından Refresh Token kopyala</span></span>
<span class="line"><span>-&gt; ImgBed&#39;e yapıştır ve kaydet</span></span></code></pre></div><h2 id="kaynaklar" tabindex="-1">Kaynaklar <a class="header-anchor" href="#kaynaklar" aria-label="Permalink to &quot;Kaynaklar&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const g=l(s,[["render",p]]);export{x as __pageData,g as default};
